"""Read-only: locked quality targets + try stream D86/flash."""
from __future__ import annotations

import json
import sys
from pathlib import Path

sys.stdout.reconfigure(encoding="utf-8", errors="replace")

from cdu_case_config import load_case_config
from hysys_api import HysysController


def main() -> None:
    print("=== LOCKED PLANT QUALITY TARGETS (do not auto-relax) ===")
    cfg = load_case_config()
    for t in cfg.get("quality_targets", []):
        if not t.get("enabled", True):
            continue
        print(
            f"{t['target_id']}: {t['stream']} {t['property']} "
            f"{t['constraint']} {t['target_value']} {t.get('unit', '')} "
            f"hard={t.get('hard')} tol={t.get('tolerance')}"
        )

    print("\n=== FINAL_TARGET FILE ===")
    ft = json.loads(Path("config/cdu_final_targets.json").read_text(encoding="utf-8"))
    for t in ft["targets"]:
        if not t.get("_enabled", True):
            continue
        print(
            f"{t['id']}: stream={t.get('stream')} type={t.get('property_type')} "
            f"{t['relationship']} {t['target_value']} tol={t['tolerance']} "
            f"locked={t['locked']} hard={t['hard']}"
        )

    print("\n=== LIVE STREAM PROPS (read-only) ===")
    h = HysysController()
    h.connect(None)
    fs = h.case.Flowsheet
    for sname in ["Naphtha", "Kerosene", "Diesel"]:
        print(f"--- {sname} ---")
        try:
            s = fs.MaterialStreams.Item(sname)
        except Exception as exc:
            print("  missing", exc)
            continue
        for coll_name in ["PetroleumProperties", "AssayProperties"]:
            try:
                coll = getattr(s, coll_name)
            except Exception:
                continue
            try:
                n = coll.Count
            except Exception as exc:
                print(f"  {coll_name}: {exc}")
                continue
            print(f"  {coll_name}.Count={n}")
            for i in range(n):
                try:
                    item = coll.Item(i)
                except Exception:
                    try:
                        item = coll.Item(i + 1)
                    except Exception:
                        continue
                name = (
                    getattr(item, "Name", None)
                    or getattr(item, "Description", None)
                    or str(item)
                )
                lname = str(name).lower()
                if not any(k in lname for k in ("d86", "flash", "astm", "tbp")):
                    continue
                val = None
                for vattr in ("Value", "CurrentValue", "CalculatedValue"):
                    try:
                        val = getattr(item, vattr)
                        break
                    except Exception:
                        pass
                print(f"    {name} = {val}")


if __name__ == "__main__":
    main()

