def scale_si_to_display(prop: Any, si_value: float | None, display_unit: str) -> float | None:
    """
    Map a COM SI-ish raw value to worksheet display using HYSYS GetValue ratio.

    Prefer ``from_calculation_to_display`` for absolute temperatures — ratio
    scaling is wrong across C/F offset. Kept for flow/energy RealVariables.
    """
    if si_value is None:
        return None
    try:
        si_value = float(si_value)
    except Exception:
        return None
    display = _get_value(prop, display_unit)
    if display is None:
        return None
    try:
        raw = float(getattr(prop, "Value", None))
    except Exception:
        raw = None
    if raw is None or abs(raw) < 1e-30:
        # Cannot form ratio — if |si| looks like already-display, return as-is
        return si_value
    return si_value * (display / raw)


def _unit_conversion_set(app: Any, set_index: int) -> Any | None:
    try:
        return app.UnitConversionSetManager.GetUnitConversionSet(int(set_index))
    except Exception:
        return None


def current_display_unit(app: Any, set_index: int = _UCS_TEMPERATURE) -> str | None:
    """HYSYS CurrentDisplayUnit for a unit set (e.g. Temperature → ``F``)."""
    ucs = _unit_conversion_set(app, set_index)
    if ucs is None:
        return None
    try:
        return str(ucs.CurrentDisplayUnit)
    except Exception:
        return None


def from_calculation_to_display(
    app: Any,
    value: float | None,
    *,
    set_index: int = _UCS_TEMPERATURE,
    display_unit: str | None = None,
) -> float | None:
    """
    Convert a HYSYS **calculation-unit** number to the case **display** unit.

    Uses HYSYS ``Unit.FromCalculationUnit`` — no Assist °C/°F algebra.
    """
    if value is None or app is None:
        return None
    try:
        value = float(value)
    except Exception:
        return None
    ucs = _unit_conversion_set(app, set_index)
    if ucs is None:
        return None
    unit_name = display_unit or current_display_unit(app, set_index)
    if not unit_name:
        return None
    try:
        for i in range(int(ucs.Count)):
            u = ucs.Item(i)
            if str(getattr(u, "Name", "")).lower() == str(unit_name).lower():
                return float(u.FromCalculationUnit(value))
    except Exception:
        return None
    return None


def temperature_to_display(app: Any, calc_value: float | None) -> float | None:
    """Absolute temperature: calculation unit → CurrentDisplayUnit (Temperature set)."""
    return from_calculation_to_display(app, calc_value, set_index=_UCS_TEMPERATURE)


def delta_temperature_to_display(app: Any, calc_delta: float | None) -> float | None:
    """Temperature difference (gaps): calculation → display via Delta Temp. set."""
    return from_calculation_to_display(app, calc_delta, set_index=_UCS_DELTA_TEMP)

def _material_stream(columns: ColumnController, stream: str) -> Any | None:
    try:
        return columns.hysys.case.Flowsheet.MaterialStreams.Item(stream)
    except Exception:
        return None


def _d86_at_percent(columns: ColumnController, stream: str, pct: float) -> float | None:
    """ASTM D86 at pct in HYSYS **display** temperature unit."""
    s = _material_stream(columns, stream)
    if s is None:
        return None
    try:
        bpt = s.BoilingPointTable
        cuts = list(bpt.CutPointCurveValue)
        d86 = list(bpt.D86CurveValue)
        if pct in cuts:
            i = cuts.index(pct)
        else:
            i = min(range(len(cuts)), key=lambda j: abs(float(cuts[j]) - pct))
        calc = float(d86[i])
    except Exception:
        return None
    if is_sentinel(calc):
        return None
    app = columns.hysys.app
    disp = temperature_to_display(app, calc)
    return disp if disp is not None else calc


def _flash_point_display(columns: ColumnController, stream: str) -> float | None:
    """Cold-prop flash in HYSYS display temperature unit (GetValue)."""
    s = _material_stream(columns, stream)
    if s is None:
        return None
    try:
        fp = s.ColdProperty.FlashPoint
    except Exception:
        return None
    unit = None
    try:
        unit = columns.hysys.display_units.temperature
    except Exception:
        unit = None
    if not unit:
        unit = current_display_unit(columns.hysys.app) or "F"
    try:
        val = float(fp.GetValue(unit))
    except Exception:
        try:
            val = float(s.ColdProperty.FlashPointValue)
            converted = temperature_to_display(columns.hysys.app, val)
            val = converted if converted is not None else val
        except Exception:
            return None
    if is_sentinel(val) or val < -1000:
        return None
    return val


def _kero_diesel_gap_display(columns: ColumnController) -> float | None:
    """Diesel D86 5% − Kero D86 95% in display delta-temperature units."""
    diesel5 = _d86_at_percent(columns, "Diesel", 5.0)
    kero95 = _d86_at_percent(columns, "Kerosene", 95.0)
    if diesel5 is None or kero95 is None:
        return None
    # Both already in display absolute T; gap is a delta — convert calc delta via HYSYS
    # Equivalent: display_diesel5 - display_kero95 (same scale as Delta Temp F)
    return float(diesel5) - float(kero95)


def _read_property(
    columns: ColumnController | None,
    stream: str,
    prop: str,
) -> tuple[float | None, str]:
    """Best-effort COM read in HYSYS worksheet / display units."""
    prop_l = prop.lower()
    petroleum = prop_l in {
        "d86_95",
        "d86",
        "d86_5",
        "flash_point",
        "rvp",
        "tbp_95",
        "gap_kero_diesel",
    } or "gap" in prop_l
    if columns is None or not stream:
        if petroleum:
            return None, "not_configured_com_path"
